// A Langlog program is a list of functions.
// The playground runs the exported fn main() -> u32.
fn main() -> u32 {
    42
}

// Functions have typed parameters and typed returns.
// Calls are direct: scale_then_add(6, 7) returns 42.
fn scale_then_add(left: u32, right: u32) -> u32 {
    left * right or(err) 0
}

fn main() -> u32 {
    scale_then_add(6, 7)
}

// let introduces bindings. mut allows assignment.
// Blocks can produce values with a trailing expression.
fn main() -> u32 {
    let start: u32 = 10;
    let mut total: u32 = start;

    total = {
        let bonus: u32 = 32;
        total + bonus or(err) 0
    };

    total
}

// read_u32 consumes one token from stdin.
// print_u32, print_bool, and print_newline write to the terminal.
fn main() -> u32 {
    let value: u32 = read_u32();
    let doubled: u32 = value * 2 or(err) 0;

    print_u32(doubled);
    print_newline();
    print_bool(doubled > value);
    print_newline();

    doubled
}

// if is a statement. Conditions are bool values.
// Comparisons, &&, ||, and early return are supported.
fn main() -> u32 {
    let value: u32 = 42;

    if (value > 10 && value < 100) || value == 7 {
        return value;
    }

    0
}

// match supports literal, wildcard, and binding patterns.
fn choose(flag: bool, code: u32) -> u32 {
    let mut value: u32 = 0;

    match flag {
        true => { value = 10; },
        false => { value = 20; }
    }

    match code {
        0 => { value = value + 1 or(err) 0; },
        7 => { value = value + 32 or(err) 0; },
        _ => { value = value + code or(err) 0; }
    }

    value
}

fn main() -> u32 {
    choose(true, 7)
}

// Ordinary u32 arithmetic returns Result<u32, ArithmeticError>.
// Use or(err) to recover and inspect failures explicitly.
fn main() -> u32 {
    let added: u32 = 40 + 2 or(err) 0;
    let subtracted: u32 = 50 - 8 or(err) 0;
    let multiplied: u32 = 6 * 7 or(err) 0;
    let divided: u32 = 84 / 2 or(err) 0;
    let remainder: u32 = 85 % 43 or(err) 0;

    let mut failures: u32 = 0;

    4294967295 + 1 or(err) {
        if err == arithmetic_overflow() {
            failures = failures + 1 or(err) 0;
        }
        0
    };

    0 - 1 or(err) {
        if err == arithmetic_underflow() {
            failures = failures + 1 or(err) 0;
        }
        0
    };

    1 / 0 or(err) {
        if err == divide_by_zero() {
            failures = failures + 1 or(err) 0;
        }
        0
    };

    1 % 0 or(err) {
        if err == remainder_by_zero() {
            failures = failures + 1 or(err) 0;
        }
        0
    };

    if added == 42 && subtracted == 42 && multiplied == 42 && divided == 42 && remainder == 42 && failures == 4 {
        return 42;
    }

    0
}

// Option<T> is either some(value) or none().
// Recovery uses the fallback only for none().
fn main() -> u32 {
    let present: Option<u32> = some(40);
    let missing: Option<u32> = none();

    let left: u32 = present or 0;
    let right: u32 = missing or 2;

    left + right or(err) 0
}

// Result<T, E> is ok(value) or err(error).
// Result recovery can bind the error payload.
fn parse_like(flag: bool) -> Result<u32, bool> {
    if flag {
        return ok(40);
    }

    err(true)
}

fn main() -> u32 {
    let recovered: u32 = parse_like(false) or(failed) {
        if failed {
            return 42;
        }
        0
    };

    recovered
}

// Tuples can be passed, returned, and compared structurally.
fn pair(value: u32, flag: bool) -> (u32, bool) {
    (value, flag)
}

fn main() -> u32 {
    let actual: (u32, bool) = pair(42, true);
    let expected: (u32, bool) = (42, true);

    if actual == expected && actual != (0, false) {
        return 42;
    }

    0
}

// Fixed arrays support constant and dynamic indexing.
// observe proves that a dynamic index is in bounds.
fn main() -> u32 {
    let values: [u32; 4] = [10, 20, 30, 40];
    let index: u32 = 2;

    observe index < 4 else {
        return 0;
    }

    values[0] + values[index] or(err) 0
}

// Arrays can contain flattened aggregate values like tuples.
// Structural equality works on indexed aggregate elements.
fn main() -> u32 {
    let pairs: [(u32, bool); 2] = [(10, false), (42, true)];
    let index: u32 = 1;

    observe index < 2 else {
        return 0;
    }

    if pairs[index] == (42, true) {
        return 42;
    }

    0
}

// for loops over fixed arrays are bounded.
// Checked arithmetic still needs recovery inside the loop.
fn main() -> u32 {
    let values: [u32; 4] = [9, 10, 11, 12];
    let mut total: u32 = 0;

    for value in values {
        total = total + value or(err) 0;
    }

    total
}

// Ranges are start-inclusive and end-exclusive.
// A range can be bound and reused as the loop iterable.
fn main() -> u32 {
    let range = 0..7;
    let mut total: u32 = 0;

    for value in range {
        total = total + value or(err) 0;
    }

    total * 2 or(err) 0
}

// observe records a fact and runs else only if the fact is false.
// The proof checker can use the fact to accept the dynamic index.
fn main() -> u32 {
    let values: [u32; 4] = [10, 20, 30, 42];
    let index: u32 = 3;

    observe index < 4 else {
        return 0;
    }

    values[index]
}
